# CoAP Constants
COAP_VERSION = 1
COAP_PORT = 5683

# CoAP Types
CON = 0  # Confirmable
NON = 1  # Non-confirmable
ACK = 2  # Acknowledgement
RST = 3  # Reset

# CoAP Methods
EMPTY = 0
GET = 1
POST = 2
PUT = 3
DELETE = 4

# CoAP Response Codes
CONTENT = (2, 5)       # 2.05 Content
CHANGED = (2, 4)       # 2.04 Changed
BAD_REQUEST = (4, 0)   # 4.00 Bad Request
NOT_FOUND = (4, 4)     # 4.04 Not Found
METHOD_NOT_ALLOWED = (4, 5)  # 4.05 Method Not Allowed

# Content Format
CONTENT_FORMAT_PLAIN = 0
CONTENT_FORMAT_JSON = 50


class CoapOption:
    def __init__(self, number, value):
        self.number = number
        self.value = value


class CoapMessage:
    def __init__(self):
        self.version = COAP_VERSION
        self.type = CON
        self.token_length = 0
        self.code_class = 0
        self.code_detail = 0
        self.message_id = 0
        self.token = b''
        self.options = []
        self.payload = b''

    @property
    def uri_path(self):
        """Extract URI path from options (option number 11)."""
        parts = []
        for opt in self.options:
            if opt.number == 11:
                parts.append(opt.value.decode('utf-8') if isinstance(opt.value, bytes) else opt.value)
        return '/' + '/'.join(parts) if parts else '/'

    @staticmethod
    def parse(data):
        """Parse raw bytes into a CoapMessage."""
        msg = CoapMessage()
        if len(data) < 4:
            return None

        first_byte = data[0]
        msg.version = (first_byte >> 6) & 0x03
        msg.type = (first_byte >> 4) & 0x03
        msg.token_length = first_byte & 0x0F

        second_byte = data[1]
        msg.code_class = (second_byte >> 5) & 0x07
        msg.code_detail = second_byte & 0x1F

        msg.message_id = struct.unpack('!H', data[2:4])[0]

        offset = 4

        if msg.token_length > 0:
            msg.token = data[offset:offset + msg.token_length]
            offset += msg.token_length

        # Parse options
        prev_option_number = 0
        while offset < len(data):
            if data[offset] == 0xFF:
                offset += 1
                msg.payload = data[offset:]
                break

            option_delta = (data[offset] >> 4) & 0x0F
            option_length = data[offset] & 0x0F
            offset += 1

            if option_delta == 13:
                option_delta = data[offset] + 13
                offset += 1
            elif option_delta == 14:
                option_delta = struct.unpack('!H', data[offset:offset + 2])[0] + 269
                offset += 2

            if option_length == 13:
                option_length = data[offset] + 13
                offset += 1
            elif option_length == 14:
                option_length = struct.unpack('!H', data[offset:offset + 2])[0] + 269
                offset += 2

            option_number = prev_option_number + option_delta
            option_value = data[offset:offset + option_length]
            offset += option_length

            msg.options.append(CoapOption(option_number, option_value))
            prev_option_number = option_number

        return msg

    def to_bytes(self):
        """Serialize CoapMessage to bytes."""
        buf = bytearray()

        first_byte = ((self.version & 0x03) << 6) | \
                     ((self.type & 0x03) << 4) | \
                     (self.token_length & 0x0F)
        buf.append(first_byte)

        second_byte = ((self.code_class & 0x07) << 5) | (self.code_detail & 0x1F)
        buf.append(second_byte)

        buf.extend(struct.pack('!H', self.message_id))

        if self.token_length > 0:
            buf.extend(self.token[:self.token_length])

        # Encode options sorted by number
        self.options.sort(key=lambda o: o.number)
        prev_option_number = 0
        for opt in self.options:
            delta = opt.number - prev_option_number
            value = opt.value if isinstance(opt.value, (bytes, bytearray)) else opt.value.encode('utf-8')
            length = len(value)

            option_byte = 0

            if delta < 13:
                option_byte |= (delta << 4)
                delta_ext = b''
            elif delta < 269:
                option_byte |= (13 << 4)
                delta_ext = bytes([delta - 13])
            else:
                option_byte |= (14 << 4)
                delta_ext = struct.pack('!H', delta - 269)

            if length < 13:
                option_byte |= length
                length_ext = b''
            elif length < 269:
                option_byte |= 13
                length_ext = bytes([length - 13])
            else:
                option_byte |= 14
                length_ext = struct.pack('!H', length - 269)

            buf.append(option_byte)
            buf.extend(delta_ext)
            buf.extend(length_ext)
            buf.extend(value)

            prev_option_number = opt.number

        if self.payload:
            buf.append(0xFF)
            if isinstance(self.payload, str):
                buf.extend(self.payload.encode('utf-8'))
            else:
                buf.extend(self.payload)

        return bytes(buf)


class DeviceState:
    """Holds the state of all device resources."""

    def __init__(self):
        self.light_state = False
        self.light_brightness = 0
        self._temp_sensor = None
        self._adc = None
        self._light_pin = None
        self._pwm_light = None
        self._init_hardware()

    def _init_hardware(self):
        """Initialize hardware peripherals. Adjust pins for your board."""
        try:
            # Try to initialize onboard temperature sensor (RP2040/ESP32)
            self._adc = machine.ADC(4)  # Internal temp sensor on RP2040
        except Exception:
            self._adc = None

        try:
            # LED/Light actuator on GPIO2 (common on ESP32/ESP8266)
            self._light_pin = machine.Pin(2, machine.Pin.OUT)
            try:
                self._pwm_light = machine.PWM(self._light_pin)
                self._pwm_light.freq(1000)
                self._pwm_light.duty_u16(0)
            except Exception:
                self._pwm_light = None
        except Exception:
            self._light_pin = None

    def read_temperature(self):
        """Read temperature from sensor. Returns float in Celsius."""
        if self._adc is not None:
            try:
                # RP2040 internal temperature sensor conversion
                reading = self._adc.read_u16()
                voltage = reading * 3.3 / 65535
                temperature = 27 - (voltage - 0.706) / 0.001721
                return round(temperature, 2)
            except Exception:
                pass

        # Fallback: simulated temperature for testing
        import urandom
        base_temp = 22.0
        variation = (urandom.getrandbits(8) - 128) / 100.0
        return round(base_temp + variation, 2)

    def set_light(self, state=None, brightness=None):
        """Control the light actuator."""
        if state is not None:
            self.light_state = bool(state)

        if brightness is not None:
            self.light_brightness = max(0, min(100, int(brightness)))
            if self.light_brightness > 0:
                self.light_state = True
            else:
                self.light_state = False

        # Apply to hardware
        if self._pwm_light is not None:
            if self.light_state:
                duty = int(self.light_brightness * 65535 / 100)
                self._pwm_light.duty_u16(duty)
            else:
                self._pwm_light.duty_u16(0)
        elif self._light_pin is not None:
            self._light_pin.value(1 if self.light_state else 0)

    def get_light_state(self):
        """Return current light state as dict."""
        return {
            "on": self.light_state,
            "brightness": self.light_brightness
        }


class CoapServer:
    """Lightweight CoAP server for MicroPython IoT devices."""

    def __init__(self, host='0.0.0.0', port=COAP_PORT):
        self.host = host
        self.port = port
        self.sock = None
        self.device = DeviceState()
        self.running = False

        # Resource handler registry: (uri_path) -> {method: handler_func}
        self.resources = {}
        self._register_default_resources()

    def _register_default_resources(self):
        """Register built-in device resources."""
        self.add_resource('/sensors/temp', get_handler=self._handle_temp_get)
        self.add_resource('/actuators/light',
                          get_handler=self._handle_light_get,
                          put_handler=self._handle_light_put)
        self.add_resource('/.well-known/core', get_handler=self._handle_discovery)

    def add_resource(self, path, get_handler=None, put_handler=None,
                     post_handler=None, delete_handler=None):
        """Register a resource with its method handlers."""
        handlers = {}
        if get_handler:
            handlers[GET] = get_handler
        if put_handler:
            handlers[PUT] = put_handler
        if post_handler:
            handlers[POST] = post_handler
        if delete_handler:
            handlers[DELETE] = delete_handler
        self.resources[path] = handlers

    def _handle_temp_get(self, request):
        """Handle GET /sensors/temp"""
        temp = self.device.read_temperature()
        payload = json.dumps({
            "temperature": temp,
            "unit": "celsius",
            "timestamp": time.time()
        })
        return CONTENT, payload, CONTENT_FORMAT_JSON

    def _handle_light_get(self, request):
        """Handle GET /actuators/light"""
        state = self.device.get_light_state()
        payload = json.dumps(state)
        return CONTENT, payload, CONTENT_FORMAT_JSON

    def _handle_light_put(self, request):
        """Handle PUT /actuators/light"""
        try:
            if request.payload:
                payload_str = request.payload.decode('utf-8') if isinstance(request.payload, bytes) else request.payload
                data = json.loads(payload_str)

                if 'on' in data:
                    self.device.set_light(state=data['on'])
                if 'brightness' in data:
                    self.device.set_light(brightness=data['brightness'])

                # Return updated state
                state = self.device.get_light_state()
                response_payload = json.dumps(state)
                return CHANGED, response_payload, CONTENT_FORMAT_JSON
            else:
                return BAD_REQUEST, b'Empty payload', CONTENT_FORMAT_PLAIN
        except (ValueError, KeyError) as e:
            return BAD_REQUEST, 'Invalid JSON: {}'.format(str(e)), CONTENT_FORMAT_PLAIN

    def _handle_discovery(self, request):
        """Handle GET /.well-known/core (CoRE Link Format discovery)."""
        links = []
        for path, handlers in self.resources.items():
            if path == '/.well-known/core':
                continue
            methods = []
            if GET in handlers:
                methods.append('GET')
            if PUT in handlers:
                methods.append('PUT')
            link = '<{}>;ct={}'.format(path, CONTENT_FORMAT_JSON)
            if 'temp' in path:
                link += ';rt="temperature-c";if="sensor"'
            elif 'light' in path:
                link += ';rt="light-actuator";if="actuator"'
            links.append(link)
        payload = ','.join(links)
        return CONTENT, payload, 40  # application/link-format

    def _build_response(self, request, code, payload=b'', content_format=None):
        """Build a CoAP response message."""
        response = CoapMessage()
        response.version = COAP_VERSION

        if request.type == CON:
            response.type = ACK
        else:
            response.type = NON

        response.code_class = code[0]
        response.code_detail = code[1]
        response.message_id = request.message_id
        response.token = request.token
        response.token_length = request.token_length

        # Add Content-Format option if specified
        if content_format is not None:
            if content_format < 256:
                cf_bytes = bytes([content_format])
            else:
                cf_bytes = struct.pack('!H', content_format)
            response.options.append(CoapOption(12, cf_bytes))

        if isinstance(payload, str):
            response.payload = payload.encode('utf-8')
        else:
            response.payload = payload

        return response

    def _get_method_code(self, request):
        """Extract method from request code."""
        if request.code_class == 0:
            return request.code_detail
        return None

    def _process_request(self, data, addr):
        """Process incoming CoAP request and return response bytes."""
        request = CoapMessage.parse(data)
        if request is None:
            return None

        method = self._get_method_code(request)
        if method is None or method == EMPTY:
            # Empty message (ping) - respond with RST or empty ACK
            response = CoapMessage()
            response.type = RST
            response.message_id = request.message_id
            return response.to_bytes()

        uri = request.uri_path
        print("[CoAP] {} {} from {}".format(
            {GET: 'GET', PUT: 'PUT', POST: 'POST', DELETE: 'DELETE'}.get(method, '?'),
            uri, addr))

        # Look up resource
        if uri in self.resources:
            handlers = self.resources[uri]
            if method in handlers:
                try:
                    code, payload, content_format = handlers[method](request)
                    response = self._build_response(request, code, payload, content_format)
                except Exception as e:
                    print("[CoAP] Handler error: {}".format(e))
                    response = self._build_response(
                        request, (5, 0),  # 5.00 Internal Server Error
                        'Internal error', CONTENT_FORMAT_PLAIN)
            else:
                response = self._build_response(
                    request, METHOD_NOT_ALLOWED,
                    'Method not allowed', CONTENT_FORMAT_PLAIN)
        else:
            response = self._build_response(
                request, NOT_FOUND,
                'Resource not found', CONTENT_FORMAT_PLAIN)